     1→const { invoke } = window.__TAURI__.core;
     2→const { getCurrentWindow } = window.__TAURI__.window;
     3→
     4→let config = {};
     5→let saveTimeout = null;
     6→
     7→async function loadConfig() {
     8→  try {
     9→    config = await invoke('get_config');
    10→    applyConfigToUI(config);
    11→  } catch (e) {
    12→    console.error('Failed to load config:', e);
    13→  }
    14→}
    15→
    16→function applyConfigToUI(cfg) {
    17→  document.getElementById('enabled').checked = cfg.enabled;
    18→  document.getElementById('mode').value = cfg.mode;
    19→  document.getElementById('interval').value = Math.round(
    20→    cfg.interval_base_ms / 1000,
    21→  ).toString();
    22→  document.getElementById('variance').value = Math.round(
    23→    cfg.interval_variance * 100,
    24→  ).toString();
    25→  document.getElementById('humanLike').checked = cfg.human_like;
    26→  document.getElementById('idleThreshold').value = (
    27→    cfg.idle_threshold_sec || 3
    28→  ).toString();
    29→  document.getElementById('breaksEnabled').checked = cfg.natural_breaks.enabled;
    30→  document.getElementById('breakChance').value =
    31→    cfg.natural_breaks.chance.toString();
    32→  document.getElementById('workHoursEnabled').checked = cfg.work_hours.enabled;
    33→  document.getElementById('workStart').value = cfg.work_hours.start;
    34→  document.getElementById('workEnd').value = cfg.work_hours.end;
    35→
    36→  updateTimeRangeVisibility();
    37→}
    38→
    39→function getConfigFromUI() {
    40→  const intervalSeconds =
    41→    parseInt(document.getElementById('interval').value) || 180;
    42→  const clampedInterval = Math.max(30, Math.min(600, intervalSeconds));
    43→  const variancePercent =
    44→    parseInt(document.getElementById('variance').value) || 50;
    45→  const clampedVariance = Math.max(0, Math.min(100, variancePercent)) / 100;
    46→  const idleThreshold =
    47→    parseInt(document.getElementById('idleThreshold').value) || 3;
    48→  const clampedIdleThreshold = Math.max(1, Math.min(30, idleThreshold));
    49→  return {
    50→    enabled: document.getElementById('enabled').checked,
    51→    mode: document.getElementById('mode').value,
    52→    interval_base_ms: clampedInterval * 1000,
    53→    interval_variance: clampedVariance,
    54→    human_like: document.getElementById('humanLike').checked,
    55→    idle_threshold_sec: clampedIdleThreshold,
    56→    work_hours: {
    57→      enabled: document.getElementById('workHoursEnabled').checked,
    58→      start: document.getElementById('workStart').value,
    59→      end: document.getElementById('workEnd').value,
    60→    },
    61→    natural_breaks: {
    62→      enabled: document.getElementById('breaksEnabled').checked,
    63→      chance: parseFloat(document.getElementById('breakChance').value),
    64→      duration_min: 15,
    65→      duration_max: 30,
    66→    },
    67→  };
    68→}
    69→
    70→function updateTimeRangeVisibility() {
    71→  const enabled = document.getElementById('workHoursEnabled').checked;
    72→  const timeRange = document.getElementById('timeRangeGroup');
    73→  timeRange.style.display = enabled ? 'flex' : 'none';
    74→}
    75→
    76→// Auto-save with debounce (like macOS Settings)
    77→function scheduleAutoSave() {
    78→  if (saveTimeout) {
    79→    clearTimeout(saveTimeout);
    80→  }
    81→  saveTimeout = setTimeout(async () => {
    82→    const newConfig = getConfigFromUI();
    83→    try {
    84→      await invoke('save_config', { config: newConfig });
    85→      console.log('Config auto-saved');
    86→    } catch (e) {
    87→      console.error('Failed to auto-save config:', e);
    88→    }
    89→  }, 300); // 300ms debounce
    90→}
    91→
    92→// Close window (settings already saved)
    93→async function closeWindow() {
    94→  // Force save before closing
    95→  if (saveTimeout) {
    96→    clearTimeout(saveTimeout);
    97→  }
    98→  const newConfig = getConfigFromUI();
    99→  try {
   100→    await invoke('save_config', { config: newConfig });
   101→  } catch (e) {
   102→    console.error('Failed to save config on close:', e);
   103→  }
   104→  try {
   105→    const win = getCurrentWindow();
   106→    await win.hide();
   107→  } catch (e) {
   108→    console.error('Failed to hide window:', e);
   109→  }
   110→}
   111→
   112→document.addEventListener('DOMContentLoaded', () => {
   113→  loadConfig();
   114→
   115→  // Add change listeners to all inputs for auto-save
   116→  const inputs = document.querySelectorAll('input, select');
   117→  inputs.forEach(input => {
   118→    const eventType = input.type === 'number' ? 'input' : 'change';
   119→    input.addEventListener(eventType, () => {
   120→      if (input.id === 'workHoursEnabled') {
   121→        updateTimeRangeVisibility();
   122→      }
   123→      scheduleAutoSave();
   124→    });
   125→  });
   126→
   127→  // Close button just closes (settings already saved)
   128→  document.getElementById('closeBtn').addEventListener('click', closeWindow);
   129→
   130→  // Handle window close button (red X)
   131→  getCurrentWindow().onCloseRequested(async event => {
   132→    event.preventDefault();
   133→    await closeWindow();
   134→  });
   135→});
